import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { ApiService } from '../../core/services/api.service';
import { ConversionHistory, PaginatedResponse } from '../../core/models/conversion.model';
import { NotificationService } from '../../core/services/notification.service';

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './dashboard.component.html',
})
export class DashboardComponent implements OnInit {
  readonly history  = signal<ConversionHistory[]>([]);
  readonly loading  = signal(true);
  readonly total    = signal(0);
  page = 1;

  constructor(
    public auth:    AuthService,
    private api:    ApiService,
    private notify: NotificationService,
  ) {}

  ngOnInit(): void { this.loadHistory(); }

  loadHistory(): void {
    this.loading.set(true);
    this.api.get<PaginatedResponse<ConversionHistory>>(`history?page=${this.page}&limit=20`)
      .subscribe({
        next: (res) => {
          this.history.set(res.data);
          this.total.set(res.pagination.total);
          this.loading.set(false);
        },
        error: () => this.loading.set(false),
      });
  }

  deleteEntry(id: string): void {
    this.api.delete<void>(`history/${id}`).subscribe({
      next: () => {
        this.history.update((h) => h.filter((e) => e._id !== id));
        this.notify.success('Deleted');
      },
      error: () => this.notify.error('Failed to delete'),
    });
  }

  toolLabel(tool: string): string {
    const map: Record<string, string> = {
      'image-to-pdf':   'Image → PDF',
      'pdf-to-word':    'PDF → Word',
      'word-to-pdf':    'Word → PDF',
      'pdf-merge':      'PDF Merge',
      'pdf-split':      'PDF Split',
      'pdf-compress':   'PDF Compress',
      'image-resize':   'Image Resize',
      'image-compress': 'Image Compress',
      'image-convert':  'Image Convert',
      'text-to-pdf':    'Text → PDF',
      'create-zip':     'Create ZIP',
    };
    return map[tool] ?? tool;
  }

  statusClass(status: string): string {
    const c: Record<string, string> = {
      completed:  'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-400',
      failed:     'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400',
      processing: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400',
      pending:    'bg-slate-100 text-slate-600 dark:bg-slate-700 dark:text-slate-400',
    };
    return c[status] ?? c['pending'];
  }

  formatDate(iso: string): string {
    return new Date(iso).toLocaleString();
  }
}
<div class="container-app py-10">

  <!-- Header -->
  <div class="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-10">
    <div>
      <h1 class="text-2xl font-bold text-slate-900 dark:text-white">Dashboard</h1>
      <p class="text-slate-500 dark:text-slate-400 mt-1">
        Welcome back, <span class="font-medium text-slate-700 dark:text-slate-200">{{ auth.user()?.name }}</span>
      </p>
    </div>
    <a routerLink="/" class="btn btn-primary">+ Convert Files</a>
  </div>

  <!-- Stats -->
  <div class="grid grid-cols-1 sm:grid-cols-3 gap-5 mb-10">
    <div class="card p-5 flex items-center gap-4">
      <div class="w-12 h-12 bg-primary-100 dark:bg-primary-950/50 rounded-xl flex items-center justify-center text-xl">📊</div>
      <div>
        <p class="text-2xl font-bold text-slate-800 dark:text-white">{{ total() }}</p>
        <p class="text-sm text-slate-500 dark:text-slate-400">Total conversions</p>
      </div>
    </div>

    <div class="card p-5 flex items-center gap-4">
      <div class="w-12 h-12 bg-emerald-100 dark:bg-emerald-950/50 rounded-xl flex items-center justify-center text-xl">✅</div>
      <div>
        <p class="text-2xl font-bold text-slate-800 dark:text-white">{{ auth.user()?.createdAt | date:'mediumDate' }}</p>
        <p class="text-sm text-slate-500 dark:text-slate-400">Member since</p>
      </div>
    </div>

    <div class="card p-5 flex items-center gap-4">
      <div class="w-12 h-12 bg-amber-100 dark:bg-amber-950/50 rounded-xl flex items-center justify-center text-xl">⭐</div>
      <div>
        <p class="text-2xl font-bold text-slate-800 dark:text-white">{{ auth.user()?.role | titlecase }}</p>
        <p class="text-sm text-slate-500 dark:text-slate-400">Account type</p>
      </div>
    </div>
  </div>

  <!-- History Table -->
  <div class="card overflow-hidden">
    <div class="px-6 py-4 border-b border-slate-100 dark:border-slate-700">
      <h2 class="font-semibold text-slate-800 dark:text-white">Conversion History</h2>
    </div>

    <!-- Loading Skeleton -->
    <div *ngIf="loading()" class="p-6 space-y-3">
      <div *ngFor="let i of [1,2,3,4,5]" class="skeleton h-12 rounded-xl"></div>
    </div>

    <!-- Empty -->
    <div *ngIf="!loading() && !history().length" class="py-16 text-center text-slate-400">
      <p class="text-4xl mb-3">📭</p>
      <p class="font-medium">No conversions yet</p>
      <a routerLink="/" class="btn btn-primary mt-4">Start Converting</a>
    </div>

    <!-- Table -->
    <div *ngIf="!loading() && history().length" class="overflow-x-auto">
      <table class="w-full text-sm">
        <thead class="bg-slate-50 dark:bg-slate-800 text-xs uppercase text-slate-500 dark:text-slate-400">
          <tr>
            <th class="text-left px-6 py-3">Tool</th>
            <th class="text-left px-6 py-3">Files</th>
            <th class="text-left px-6 py-3">Status</th>
            <th class="text-left px-6 py-3">Date</th>
            <th class="px-6 py-3"></th>
          </tr>
        </thead>
        <tbody class="divide-y divide-slate-100 dark:divide-slate-700">
          <tr *ngFor="let entry of history()"
            class="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">

            <td class="px-6 py-3.5 font-medium text-slate-700 dark:text-slate-200">
              {{ toolLabel(entry.tool) }}
            </td>

            <td class="px-6 py-3.5 text-slate-500 dark:text-slate-400">
              {{ entry.inputFiles[0]?.originalName || '—' }}
              <span *ngIf="entry.inputFiles.length > 1" class="text-xs text-slate-400">
                +{{ entry.inputFiles.length - 1 }} more
              </span>
            </td>

            <td class="px-6 py-3.5">
              <span [class]="statusClass(entry.status)" class="badge">{{ entry.status }}</span>
            </td>

            <td class="px-6 py-3.5 text-slate-400 text-xs whitespace-nowrap">
              {{ formatDate(entry.createdAt) }}
            </td>

            <td class="px-6 py-3.5 text-right">
